mapper.select:
SELECT
,
(

    (CASE
    WHEN title LIKE CONCAT('%', #{substring}, '%') THEN ${substring.length()}
    WHEN author LIKE CONCAT('%', #{substring}, '%') THEN ${substring.length()}
    WHEN publisher LIKE CONCAT('%', #{substring}, '%') THEN ${substring.length()}
    WHEN category LIKE CONCAT('%', #{substring}, '%') THEN ${substring.length()}
    WHEN description LIKE CONCAT('%', #{substring}, '%') THEN ${substring.length()}
    ELSE 0
    END)

) AS score
FROM book
WHERE

    title LIKE CONCAT('%', #{substring}, '%')
    OR author LIKE CONCAT('%', #{substring}, '%')
    OR publisher LIKE CONCAT('%', #{substring}, '%')
    OR category LIKE CONCAT('%', #{substring}, '%')
    OR description LIKE CONCAT('%', #{substring}, '%')

ORDER BY score DESC

